#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;

void preOrderTraversal(Node* node) {
    if (node == NULL) return;
    printf("%d ", node->value);
    preOrderTraversal(node->left);
    preOrderTraversal(node->right);
}

int main() {
    int N;
    scanf("%d", &N);
    Node** nodes = (Node**)malloc(N * sizeof(Node*));
    for (int i = 0; i < N; i++) {
        nodes[i] = (Node*)malloc(sizeof(Node));
        scanf("%d %d %d", &nodes[i]->value, &nodes[i]->left, &nodes[i]->right);
        nodes[i]->left = nodes[i]->left == -1 ? NULL : nodes[nodes[i]->left - 1];
        nodes[i]->right = nodes[i]->right == -1 ? NULL : nodes[nodes[i]->right - 1];
    }
    preOrderTraversal(nodes[0]);
    return 0;
}

